import math

def is_pentagonal(n):
    if n < 1: return False
    # A number x is pentagonal if (sqrt(24x + 1) + 1) / 6 is an integer
    val = (math.sqrt(24 * n + 1) + 1) / 6
    return val.is_integer()

def solution():
    p = set()
    i = 1
    while True:
        pi = i * (3 * i - 1) // 2
        for pj in p:
            # If we find a pair, we return the difference immediately
            # as it is likely the minimum given the iteration order
            if is_pentagonal(pi - pj) and is_pentagonal(pi + pj):
                return pi - pj
        p.add(pi)
        i += 1


if __name__ == "__main__":
    print(solution())
